SELECT 'archived_total' AS probe, COUNT(*) AS n FROM payments WHERE basket_archived=1;
SELECT 'card_share' AS probe, payment_method_fingerprint AS k1, COUNT(*) AS rows_n, COUNT(DISTINCT customer_id) AS cust_n FROM payments WHERE basket_archived=1 GROUP BY payment_method_fingerprint HAVING COUNT(DISTINCT customer_id) > 1 ORDER BY cust_n DESC, rows_n DESC LIMIT 50;
SELECT 'device_share' AS probe, device_fingerprint AS k1, COUNT(*) AS rows_n, COUNT(DISTINCT customer_id) AS cust_n FROM payments WHERE basket_archived=1 GROUP BY device_fingerprint HAVING COUNT(DISTINCT customer_id) > 1 ORDER BY cust_n DESC, rows_n DESC LIMIT 50;
SELECT 'card_device_share' AS probe, payment_method_fingerprint AS k1, device_fingerprint AS k2, COUNT(*) AS rows_n, COUNT(DISTINCT customer_id) AS cust_n FROM payments WHERE basket_archived=1 GROUP BY payment_method_fingerprint, device_fingerprint HAVING COUNT(DISTINCT customer_id) > 1 ORDER BY cust_n DESC, rows_n DESC LIMIT 50;
SELECT 'coord_cluster' AS probe, ROUND(observed_lat,4) AS lat4, ROUND(observed_lon,4) AS lon4, COUNT(*) AS rows_n, COUNT(DISTINCT customer_id) AS cust_n FROM payments WHERE basket_archived=1 GROUP BY ROUND(observed_lat,4), ROUND(observed_lon,4) HAVING COUNT(DISTINCT customer_id) > 1 ORDER BY cust_n DESC, rows_n DESC LIMIT 50;
